output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?dish ?dishLabel WHERE {
  ?dish wdt:P495 wd:Q217 ; rdfs:label ?dishLabel .
  FILTER(LANG(?dishLabel) = "en")
  FILTER NOT EXISTS {
    ?dish wdt:P527 ?ingredient .
    ?ingredient wdt:P31 ?class .
    ?class wdt:P279 * wd:Q16824 .
  }
  FILTER NOT EXISTS {
    ?dish wdt:P527 wd:Q223 .
  }
}
LIMIT 10

